using LJCNetCommon;

var dbColumnBool = new DbColumn("TestBool", "1", NetCommon.TypeBoolean);
var dbColumnDate = new DbColumn("TestDate", DateTime.Now()
, NetCommon.TypeDateTime);
var dbColumnString = new DbColumn("TestString", "string");

// Creates a US Census soundex value.
private static void Soundex()
{
  var text = "Clark";
  var result = LJCNetString.Soundex(text);
  // result = "C462"

  text = "Klum";
  result = LJCNetString.Soundex(text);
  // result = "K450"

  text = "Rodriguez";
  result = LJCNetString.Soundex(text);
  // result = "R362";
}
